const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');

// Find Documents root folder
const documentsFolder = items.find(it => !it.isDeleted && it.itemType === 'folder' && it.parentId == null && it.name === 'Documents');

// Find 'Invoices 2024' folder under Documents
let invoicesFolder = null;
if (documentsFolder) {
  invoicesFolder = items.find(it => !it.isDeleted && it.itemType === 'folder' && it.name === 'Invoices 2024' && it.parentId === documentsFolder.id);
}

// Qualifying PDF invoices in Documents: pdf, name starts with 'Invoice_2024', anywhere under /Documents
const qualifyingInvoices = items.filter(it => {
  if (it.isDeleted || it.itemType !== 'file' || it.fileType !== 'pdf') return false;
  if (!it.name || !it.name.startsWith('Invoice_2024')) return false;
  const p = it.path || '';
  return p.startsWith('/Documents');
});

// Those qualifying invoices that ended up inside the Invoices 2024 folder
let movedIntoInvoices = [];
if (invoicesFolder) {
  movedIntoInvoices = qualifyingInvoices.filter(it => it.parentId === invoicesFolder.id);
}

// CP1 (0.4): 'Invoices 2024' folder exists under Documents AND is starred
checkpoints.push({
  passed: !!(invoicesFolder && invoicesFolder.starred === true && invoicesFolder.parentId === (documentsFolder && documentsFolder.id)),
  weight: 0.4
});

// CP2 (0.3): At least 5 qualifying 'Invoice_2024' PDFs (from Documents) are inside 'Invoices 2024'
checkpoints.push({
  passed: invoicesFolder != null && movedIntoInvoices.length >= 5,
  weight: 0.3
});

// CP3 (0.3): Exactly 5 qualifying invoices were placed into 'Invoices 2024'
checkpoints.push({
  passed: invoicesFolder != null && movedIntoInvoices.length === 5,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');
const collabs = JSON.parse(localStorage.getItem('collaborator_permissions') || '[]');
const links = JSON.parse(localStorage.getItem('share_links') || '[]');

// Find all project folders under /Projects
const projectsRoot = items.find(it => !it.isDeleted && it.itemType === 'folder' && it.parentId == null && it.name === 'Projects');
let targetFolder = null;
if (projectsRoot) {
  const projectFolders = items.filter(it => !it.isDeleted && it.itemType === 'folder' && (it.path || '').startsWith('/Projects/'));
  // Among these, find one that already has at least one viewer and one editor collaborator
  targetFolder = projectFolders.find(f => {
    const cForFolder = collabs.filter(c => c.storageItemId === f.id);
    const hasViewer = cForFolder.some(c => c.role === 'viewer');
    const hasEditor = cForFolder.some(c => c.role === 'editor');
    return hasViewer && hasEditor;
  }) || null;
}

let folderCollabs = [];
let folderLink = null;
if (targetFolder) {
  folderCollabs = collabs.filter(c => c.storageItemId === targetFolder.id);
  folderLink = links.find(l => l.storageItemId === targetFolder.id && l.isEnabled);
}

// Helper to find specific collaborators
const alexViewer = folderCollabs.find(c => c.collaboratorName === 'alex_viewer' && c.role === 'viewer');
const jamieEditor = folderCollabs.find(c => c.collaboratorName === 'jamie_editor' && c.role === 'editor');

// CP1 (0.3): Correct folder identified AND both collaborators present with correct roles and download allowed
checkpoints.push({
  passed: !!(targetFolder && alexViewer && jamieEditor && alexViewer.allowDownload === true && jamieEditor.allowDownload === true),
  weight: 0.3
});

// CP2 (0.3): Enabled share link exists for that folder with accessLevel 'only_invited_people'
checkpoints.push({
  passed: !!(folderLink && folderLink.accessLevel === 'only_invited_people' && folderLink.isEnabled === true),
  weight: 0.3
});

// CP3 (0.4): That link grants edit permission, allows download, and expires by end of 2025
let cp3Passed = false;
if (folderLink && folderLink.expiresAt) {
  const expMs = Date.parse(folderLink.expiresAt);
  const deadlineMs = Date.parse('2025-12-31T23:59:59Z');
  cp3Passed = folderLink.permission === 'can_edit' && folderLink.allowDownload === true && !Number.isNaN(expMs) && expMs <= deadlineMs;
}
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');
const filterParams = JSON.parse(localStorage.getItem('task3_videoFilterParams') || 'null');
const moveParams = JSON.parse(localStorage.getItem('task3_archiveMoveParams') || 'null');
const deleteParams = JSON.parse(localStorage.getItem('task3_permanentDeleteParams') || 'null');

const SIZE_THRESHOLD = 524288000; // 500 MB in bytes

// CP1 (0.3): User used correct filter and sort to identify top 3 large video files
let cp1Passed = false;
if (filterParams && filterParams.filtersUsed) {
  const f = filterParams.filtersUsed;
  const hasCorrectFileType = f.fileType === 'video';
  const hasMinSize = typeof f.minSizeBytes === 'number' && f.minSizeBytes >= SIZE_THRESHOLD;
  const correctSortBy = (filterParams.sortBy || 'size') === 'size';
  const correctDirection = (filterParams.sortDirection || 'desc') === 'desc';
  const topThreeIds = Array.isArray(filterParams.topThreeIds) ? filterParams.topThreeIds : [];
  cp1Passed = hasCorrectFileType && hasMinSize && correctSortBy && correctDirection && topThreeIds.length === 3;
}
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

const topThreeIds = filterParams && Array.isArray(filterParams.topThreeIds) ? filterParams.topThreeIds : [];

// CP2 (0.35): The two largest (first two IDs) were moved into an 'Archive' folder under Videos
let cp2Passed = false;
if (moveParams && topThreeIds.length === 3) {
  const movedIds = Array.isArray(moveParams.movedItemIds) ? moveParams.movedItemIds : [];
  const destFolder = items.find(it => it.id === moveParams.destinationFolderId);
  const destPath = moveParams.destinationPath || (destFolder && destFolder.path) || '';

  const destIsArchiveUnderVideos = !!(destFolder && destFolder.itemType === 'folder' && !destFolder.isDeleted && destFolder.name === 'Archive' && destPath.startsWith('/Videos/Archive'));

  const firstTwoIds = topThreeIds.slice(0, 2);
  const bothMoved = firstTwoIds.every(id => movedIds.includes(id));

  const bothNowInArchive = firstTwoIds.every(id => {
    const it = items.find(x => x.id === id);
    return it && !it.isDeleted && it.parentId === (destFolder && destFolder.id) && (it.path || '').startsWith(destPath);
  });

  cp2Passed = destIsArchiveUnderVideos && bothMoved && bothNowInArchive;
}
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.35): The third-largest (third ID) was permanently deleted
let cp3Passed = false;
if (deleteParams && topThreeIds.length === 3) {
  const deletedIds = Array.isArray(deleteParams.permanentlyDeletedItemIds) ? deleteParams.permanentlyDeletedItemIds : [];
  const thirdId = topThreeIds[2];
  const thirdListedAsDeleted = deletedIds.includes(thirdId);
  const thirdMissingFromStorage = !items.some(it => it.id === thirdId);
  cp3Passed = thirdListedAsDeleted && thirdMissingFromStorage;
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');
const links = JSON.parse(localStorage.getItem('share_links') || '[]');

// Find the single root-level PDF (parentId == null, fileType 'pdf')
const rootPdfs = items.filter(it => !it.isDeleted && it.itemType === 'file' && it.parentId == null && it.fileType === 'pdf');
const targetFile = rootPdfs.length === 1 ? rootPdfs[0] : rootPdfs[0] || null;

let link = null;
if (targetFile) {
  link = links.find(l => l.storageItemId === targetFile.id && l.isEnabled);
}

// CP1 (0.5): Enabled public link for the root PDF with view-only and download disabled
const cp1Passed = !!(link && link.accessLevel === 'anyone_with_link' && link.permission === 'can_view' && link.allowDownload === false && link.isEnabled === true);
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): That link expires on or before end of June 2025
let cp2Passed = false;
if (link && link.expiresAt) {
  const expMs = Date.parse(link.expiresAt);
  const deadlineMs = Date.parse('2025-06-30T23:59:59Z');
  cp2Passed = !Number.isNaN(expMs) && expMs <= deadlineMs;
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');

// Baseline "now" from scenario: 2026-03-03T09:00:00Z
const nowMs = Date.parse('2026-03-03T09:00:00Z');
const windowMs = 60 * 24 * 60 * 60 * 1000; // 60 days in ms
const cutoffMs = nowMs - windowMs;

// Find Reports root folder
const reportsFolder = items.find(it => !it.isDeleted && it.itemType === 'folder' && it.parentId == null && it.name === 'Reports');

// Find 'Q3 Reports' subfolder under Reports
let q3Folder = null;
if (reportsFolder) {
  q3Folder = items.find(it => !it.isDeleted && it.itemType === 'folder' && it.name === 'Q3 Reports' && it.parentId === reportsFolder.id);
}

// Qualifying spreadsheets: fileType 'spreadsheet', name includes 'Q3' (case-insensitive), modified within last 60 days
const qualifying = items.filter(it => {
  if (it.isDeleted || it.itemType !== 'file' || it.fileType !== 'spreadsheet') return false;
  if (!it.name || !/Q3/i.test(it.name)) return false;
  const mMs = Date.parse(it.modifiedAt || '');
  if (Number.isNaN(mMs)) return false;
  return mMs >= cutoffMs && mMs <= nowMs;
});

qualifying.sort((a, b) => Date.parse(b.modifiedAt || '') - Date.parse(a.modifiedAt || ''));
const top3 = qualifying.slice(0, 3);

// CP1 (0.3): 'Q3 Reports' folder exists directly under Reports
checkpoints.push({
  passed: !!(q3Folder && q3Folder.parentId === (reportsFolder && reportsFolder.id)),
  weight: 0.3
});

// CP2 (0.35): At least one of the three newest qualifying spreadsheets is inside 'Q3 Reports'
let cp2Passed = false;
if (q3Folder && top3.length > 0) {
  const inFolder = top3.filter(it => it.parentId === q3Folder.id);
  cp2Passed = inFolder.length >= 1;
}
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.35): All three of the newest qualifying spreadsheets are inside 'Q3 Reports'
let cp3Passed = false;
if (q3Folder && top3.length === 3) {
  cp3Passed = top3.every(it => it.parentId === q3Folder.id);
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');
const versions = JSON.parse(localStorage.getItem('file_versions') || '[]');

// Find the only top-level document with version history enabled
const versionedRootDocs = items.filter(it => !it.isDeleted && it.itemType === 'file' && it.parentId == null && it.hasVersionHistory);
const targetFile = versionedRootDocs[0] || null;

// Find versions for this file created in January 2024
let janVersions = [];
let newerJanVersion = null;
if (targetFile) {
  const fileVers = versions.filter(v => v.storageItemId === targetFile.id);
  janVersions = fileVers.filter(v => {
    const t = Date.parse(v.createdAt || '');
    if (Number.isNaN(t)) return false;
    const d = new Date(t);
    const y = d.getUTCFullYear();
    const m = d.getUTCMonth(); // 0-based
    return y === 2024 && m === 0; // January
  });
  if (janVersions.length > 0) {
    janVersions.sort((a, b) => Date.parse(a.createdAt || '') - Date.parse(b.createdAt || ''));
    newerJanVersion = janVersions[janVersions.length - 1];
  }
}

// CP1 (0.4): Target file exists AND its currentVersionId points to the newer January 2024 version, which is marked isCurrent
let cp1Passed = false;
if (targetFile && newerJanVersion) {
  const currentVersion = versions.find(v => v.id === targetFile.currentVersionId);
  cp1Passed = !!(currentVersion && currentVersion.id === newerJanVersion.id && currentVersion.isCurrent === true && targetFile.currentVersionId === newerJanVersion.id);
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.3): All other versions for this file are not marked as current
let cp2Passed = false;
if (targetFile) {
  const fileVers = versions.filter(v => v.storageItemId === targetFile.id);
  const nonCurrentOk = fileVers.every(v => v.id === (targetFile.currentVersionId) ? v.isCurrent === true : v.isCurrent === false);
  cp2Passed = nonCurrentOk;
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.3): File's modifiedAt matches the createdAt of the newer January version (restore behavior)
let cp3Passed = false;
if (targetFile && newerJanVersion) {
  const fileMod = Date.parse(targetFile.modifiedAt || '');
  const verCreated = Date.parse(newerJanVersion.createdAt || '');
  cp3Passed = !Number.isNaN(fileMod) && !Number.isNaN(verCreated) && fileMod === verCreated;
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const items = JSON.parse(localStorage.getItem('storage_items') || '[]');

// Two most recently opened PDFs
const pdfs = items.filter(it => !it.isDeleted && it.itemType === 'file' && it.fileType === 'pdf' && it.lastOpenedAt);
pdfs.sort((a, b) => Date.parse(b.lastOpenedAt || '') - Date.parse(a.lastOpenedAt || ''));
const top2Pdfs = pdfs.slice(0, 2);

// Most recently modified project subfolder (folder under /Projects)
const projectFolders = items.filter(it => !it.isDeleted && it.itemType === 'folder' && (it.path || '').startsWith('/Projects/') && it.id !== items.find(r => r.name === 'Projects' && r.parentId == null)?.id);
projectFolders.sort((a, b) => Date.parse(b.modifiedAt || '') - Date.parse(a.modifiedAt || ''));
const newestProjectFolder = projectFolders[0] || null;

// CP1 (0.5): The two most recently opened PDFs are available offline
let cp1Passed = false;
if (top2Pdfs.length === 2) {
  cp1Passed = top2Pdfs.every(it => it.isAvailableOffline === true);
}
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): The most recently modified project subfolder is available offline
let cp2Passed = false;
if (newestProjectFolder) {
  cp2Passed = newestProjectFolder.isAvailableOffline === true;
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const incoming = JSON.parse(localStorage.getItem('incoming_shares') || '[]');
const items = JSON.parse(localStorage.getItem('storage_items') || '[]');
const collabs = JSON.parse(localStorage.getItem('collaborator_permissions') || '[]');
const labels = JSON.parse(localStorage.getItem('labels') || '[]');
const itemLabels = JSON.parse(localStorage.getItem('item_labels') || '[]');

// Pair incoming shares with their items
let shareItems = incoming.map(sh => {
  const item = items.find(it => it.id === sh.storageItemId) || null;
  return { share: sh, item };
});

// Sort by sharedDate desc
shareItems.sort((a, b) => Date.parse(b.share.sharedDate || '') - Date.parse(a.share.sharedDate || ''));

// Find most recently shared individual file (not folder)
const targetPair = shareItems.find(p => p.item && !p.item.isDeleted && p.item.itemType === 'file') || null;
const targetItem = targetPair ? targetPair.item : null;

// Find viewer collaborator(s) for this item
let viewerCollab = null;
if (targetItem) {
  const cForItem = collabs.filter(c => c.storageItemId === targetItem.id && c.role === 'viewer');
  viewerCollab = cForItem[0] || null;
}

// Find 'Confidential' label id dynamically
const confidentialLabel = labels.find(l => (l.name || '').toLowerCase() === 'confidential');
let hasConfidential = false;
if (targetItem && confidentialLabel) {
  hasConfidential = itemLabels.some(il => il.storageItemId === targetItem.id && il.labelId === confidentialLabel.id);
}

// CP1 (0.5): For the newest shared file, its viewer-level collaborator has downloading disabled
const cp1Passed = !!(targetItem && viewerCollab && viewerCollab.allowDownload === false);
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): That same file has the 'Confidential' label applied
const cp2Passed = !!(targetItem && hasConfidential);
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
